const ctx = items[0].json;

function nowIso() { return new Date().toISOString(); }
function ensureArray(value) { return Array.isArray(value) ? value : []; }
function clamp(value, min, max, fallback) {
  const n = Number(value);
  if (!Number.isFinite(n)) return fallback;
  if (n < min) return min;
  if (n > max) return max;
  return n;
}
function shortText(value, maxLen = 320) {
  const text = typeof value === 'string' ? value : JSON.stringify(value || '');
  return text.length <= maxLen ? text : text.slice(0, maxLen - 3) + '...';
}
function sanitizeSlug(value) {
  return String(value || 'workflow').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').slice(0, 80) || 'workflow';
}
function yamlEscape(value) { return String(value || '').replace(/\n/g, ' ').replace(/"/g, '\\"'); }

function addStage(step, stage, status, inputRef, outputRef, quality, notes, issueCount = 0) {
  ctx.stage_logs.push({
    step,
    stage,
    status,
    input_ref: inputRef,
    output_ref: outputRef,
    quality_score: Number.isFinite(Number(quality)) ? Number(quality) : 0,
    notes: String(notes || ''),
    issues: Number.isFinite(Number(issueCount)) ? Number(issueCount) : 0,
    model_used: ctx.model_used,
    ts: nowIso(),
  });
  ctx.model_trace = ensureArray(ctx.model_trace);
  ctx.model_trace.push({ step, stage, model_used: ctx.model_used, ts: nowIso() });
}

function extractJsonCandidate(rawText) {
  if (typeof rawText !== 'string') throw new Error('Model output is not a string');
  const fenced = rawText.match(/```(?:json)?\s*([\s\S]*?)```/i);
  const text = (fenced ? fenced[1] : rawText).trim();
  try { return JSON.parse(text); } catch {}
  const objStart = text.indexOf('{');
  const arrStart = text.indexOf('[');
  const starts = [objStart, arrStart].filter((v) => v >= 0);
  if (!starts.length) throw new Error('No JSON start found');
  const start = Math.min(...starts);
  const openChar = text[start];
  const closeChar = openChar === '{' ? '}' : ']';
  let depth = 0, inString = false, escaped = false;
  for (let i = start; i < text.length; i++) {
    const ch = text[i];
    if (inString) {
      if (escaped) escaped = false;
      else if (ch === '\\') escaped = true;
      else if (ch === '"') inString = false;
      continue;
    }
    if (ch === '"') { inString = true; continue; }
    if (ch === openChar) depth += 1;
    if (ch === closeChar) {
      depth -= 1;
      if (depth === 0) return JSON.parse(text.slice(start, i + 1));
    }
  }
  throw new Error('Could not extract valid JSON payload');
}

async function callOllamaRaw(systemPrompt, userPrompt, options = {}) {
  const temperature = Number.isFinite(Number(options.temperature)) ? Number(options.temperature) : 0.3;
  const numPredict = Number.isFinite(Number(options.num_predict)) ? Number(options.num_predict) : 180;
  const numCtx = Number.isFinite(Number(options.num_ctx)) ? Number(options.num_ctx) : 768;
  const timeout = Number.isFinite(Number(options.timeout)) ? Number(options.timeout) : 900000;
  const maxAttempts = Number.isFinite(Number(options.max_attempts)) ? Number(options.max_attempts) : 3;
  const keepAlive = String(options.keep_alive || '30m');

  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
    try {
      const data = await this.helpers.httpRequest({
        method: 'POST',
        url: (($env.OLLAMA_BASE_URL || 'http://host.docker.internal:11434').replace(/\/+$/, '') + '/api/chat'),
        body: {
          model: ctx.model_used,
          stream: false,
          keep_alive: keepAlive,
          messages: [
            { role: 'system', content: systemPrompt },
            { role: 'user', content: userPrompt },
          ],
          options: { temperature, num_predict: numPredict, num_ctx: numCtx },
        },
        json: true,
        timeout,
      });
      const text = data?.message?.content || data?.response;
      if (!text) throw new Error('Ollama response has no content');
      return { text: String(text), model_used: ctx.model_used };
    } catch (error) {
      const details = [error?.message || '', error?.response?.data?.error || ''].filter(Boolean).join(' | ');
      const retryable = /status code\s+5[0-9]{2}|runner process has terminated|llama runner|timed out|socket hang up|econnreset|context canceled|connection reset|no content|response has no content|empty response/i.test(details);
      if (retryable && attempt < maxAttempts) {
        await new Promise((resolve) => setTimeout(resolve, 2500 * attempt));
        continue;
      }
      throw new Error('Ollama call failed (attempt=' + attempt + '/' + maxAttempts + '): ' + (details || 'unknown'));
    }
  }
}
async function callOllamaJson(systemPrompt, userPrompt, options = {}) {
  const raw = await callOllamaRaw.call(this, systemPrompt, userPrompt, options);
  return { parsed: extractJsonCandidate(raw.text), raw_text: raw.text, model_used: raw.model_used };
}
async function callOllamaText(systemPrompt, userPrompt, options = {}) {
  const raw = await callOllamaRaw.call(this, systemPrompt, userPrompt, options);
  return { text: raw.text, model_used: raw.model_used };
}

async function addStageSummary(step, stage, payload) {
  const summaryPrompt = [ctx.prompts.qwen_step_summary, 'Schritt: ' + step + ' - ' + stage, 'Payload: ' + shortText(payload, 2500), 'Antworte nur mit einer kompakten Zusammenfassung.'].join('\n\n');
  let summary = '';
  try {
    const res = await callOllamaText.call(this, 'Du schreibst knappe Workflow-Zusammenfassungen. Keine Markdown-Listen.', summaryPrompt, { temperature: 0.1, num_predict: 40, num_ctx: 256, timeout: 90000, max_attempts: 2 });
    summary = shortText(res.text.replace(/\s+/g, ' ').trim(), 280);
  } catch (error) {
    summary = 'Zusammenfassung fehlgeschlagen: ' + shortText(error.message || 'unknown', 180);
  }
  ctx.stage_summaries.push({ step, stage, summary });
}

function assertType(label, value, type) {
  if (type === 'array') { if (!Array.isArray(value)) throw new Error(label + ' must be an array'); return; }
  if (type === 'object') { if (!value || typeof value !== 'object' || Array.isArray(value)) throw new Error(label + ' must be an object'); return; }
  if (typeof value !== type) throw new Error(label + ' must be type ' + type);
}
function assertStringArray(label, arr, minLen = 0) {
  assertType(label, arr, 'array');
  if (arr.length < minLen) throw new Error(label + ' requires at least ' + minLen + ' item(s)');
  for (let i = 0; i < arr.length; i++) if (typeof arr[i] !== 'string') throw new Error(label + '[' + i + '] must be string');
}
function validatePlatformResearch(label, payload) {
  assertType(label, payload, 'object');
  for (const key of ['core_problem', 'proof_points']) if (!(key in payload)) throw new Error(label + ' missing key: ' + key);
  assertType(label + '.core_problem', payload.core_problem, 'string');
  assertStringArray(label + '.proof_points', payload.proof_points, 1);
}
function validateTopicBrief(data) {
  const required = ['topic', 'angle', 'why_now', 'platform_recommendation', 'confidence'];
  for (const key of required) if (!(key in data)) throw new Error('topic_brief missing key: ' + key);
}
function validateDraftPackageStrict(payload) {
  assertType('draft_package', payload, 'object');
  if (!('topic' in payload) || !('drafts' in payload)) throw new Error('draft_package missing required keys');
  assertType('draft_package.topic', payload.topic, 'string');
  assertType('draft_package.drafts', payload.drafts, 'array');
  if (payload.drafts.length < 2) throw new Error('draft_package.drafts requires at least 2 drafts');
}

function compactEvidence(packets, limit = 6) {
  return ensureArray(packets).slice(0, limit).map((packet) => ({
    query: shortText(packet.query || '', 80),
    title: shortText(packet.title || '', 100),
    url: shortText(packet.url || '', 180),
    summary: shortText(packet.summary || '', 140),
    key_points: ensureArray(packet.key_points).slice(0, 1).map((p) => shortText(p, 90)),
    source_type: shortText(packet.source_type || '', 40),
  }));
}
function compactDraftPackage(pkg) {
  const draftPackage = pkg && typeof pkg === 'object' ? pkg : {};
  return {
    topic: shortText(draftPackage.topic || '', 120),
    drafts: ensureArray(draftPackage.drafts).slice(0, 2).map((draft) => ({
      platform: shortText(draft.platform || '', 20),
      title: shortText(draft.title || '', 120),
      body: shortText(draft.body || '', 900),
      cta: shortText(draft.cta || '', 140),
      hashtags: ensureArray(draft.hashtags).slice(0, 8).map((tag) => shortText(tag, 30)),
    })),
  };
}
function normalizeDraftPackage(candidate, fallbackTopic) {
  if (!candidate || !Array.isArray(candidate.drafts)) throw new Error('draft_package invalid: drafts missing');
  const drafts = candidate.drafts.map((draft, index) => ({
    platform: String(draft.platform || '').toLowerCase() || (index === 0 ? 'linkedin' : 'reddit'),
    title: String(draft.title || ('Draft ' + (index + 1))),
    body: String(draft.body || ''),
    cta: String(draft.cta || ''),
    hashtags: ensureArray(draft.hashtags).map((h) => String(h)),
    notes: ensureArray(draft.notes).map((n) => String(n)),
  }));
  return { topic: String(candidate.topic || fallbackTopic || 'Workflow Thema'), drafts };
}
function normalizeCritique(candidate, stage) {
  const src = candidate?.critique_report ? candidate.critique_report : candidate;
  if (!src || typeof src !== 'object') throw new Error(stage + ' critique invalid');
  const issues = ensureArray(src.issues).map((issue) => ({
    severity: ['low', 'medium', 'high'].includes(issue?.severity) ? issue.severity : 'medium',
    message: String(issue?.message || 'unspecified issue'),
  }));
  return { stage: String(src.stage || stage), score: clamp(src.score, 0, 10, 6), issues, improved_draft: src.improved_draft || {} };
}

const evidencePackets = ensureArray(ctx.artifacts?.evidence_packets);
if (!evidencePackets.length) throw new Error('Missing evidence packets from WF10');

const stage3Prompt = [ctx.prompts.agent2_topic_fit, 'Return JSON only.', 'Evidence packets: ' + JSON.stringify(compactEvidence(evidencePackets, 4))].join('\n\n');
const stage3 = await callOllamaJson.call(this, 'You are a product strategy reviewer. Return valid JSON only.', stage3Prompt, { temperature: 0.2, num_predict: 110, num_ctx: 768, timeout: 180000, max_attempts: 3 });
const topicBrief = stage3.parsed;
validateTopicBrief(topicBrief);
topicBrief.confidence = clamp(topicBrief.confidence, 0, 1, 0.5);
if (!Array.isArray(topicBrief.platform_recommendation) || !topicBrief.platform_recommendation.length) topicBrief.platform_recommendation = ['linkedin', 'reddit'];
ctx.artifacts.topic_brief = topicBrief;
addStage(3, 'build_topic_brief', 'ok', 'run/' + ctx.run_id + '/stage3/input', 'run/' + ctx.run_id + '/stage3/topic_brief', topicBrief.confidence, shortText(topicBrief.angle, 160));
await addStageSummary.call(this, 3, 'build_topic_brief', JSON.stringify(topicBrief));

const stage4Prompt = [ctx.prompts.platform_linkedin, 'Return JSON only.', 'Topic brief: ' + shortText(JSON.stringify(topicBrief), 1200), 'Evidence packets: ' + JSON.stringify(compactEvidence(evidencePackets, 3))].join('\n\n');
const stage4 = await callOllamaJson.call(this, 'You format research for LinkedIn. Return valid JSON only.', stage4Prompt, { temperature: 0.2, num_predict: 110, num_ctx: 768, timeout: 150000, max_attempts: 3 });
const linkedinResearch = stage4.parsed;
validatePlatformResearch('linkedin_research', linkedinResearch);
ctx.artifacts.linkedin_research = linkedinResearch;
addStage(4, 'build_linkedin_fokus', 'ok', 'run/' + ctx.run_id + '/stage4/input', 'run/' + ctx.run_id + '/stage4/linkedin_research', 8.4, shortText(linkedinResearch.core_problem || 'linkedin_research_ready', 160));
await addStageSummary.call(this, 4, 'build_linkedin_fokus', JSON.stringify(linkedinResearch));

const stage5Prompt = [ctx.prompts.platform_reddit, 'Return JSON only.', 'Topic brief: ' + shortText(JSON.stringify(topicBrief), 1200), 'Evidence packets: ' + JSON.stringify(compactEvidence(evidencePackets, 3))].join('\n\n');
const stage5 = await callOllamaJson.call(this, 'You format research for Reddit. Return valid JSON only.', stage5Prompt, { temperature: 0.2, num_predict: 110, num_ctx: 768, timeout: 150000, max_attempts: 3 });
const redditResearch = stage5.parsed;
validatePlatformResearch('reddit_research', redditResearch);
ctx.artifacts.reddit_research = redditResearch;
addStage(5, 'build_reddit_fokus', 'ok', 'run/' + ctx.run_id + '/stage5/input', 'run/' + ctx.run_id + '/stage5/reddit_research', 8.4, shortText(redditResearch.core_problem || 'reddit_research_ready', 160));
await addStageSummary.call(this, 5, 'build_reddit_fokus', JSON.stringify(redditResearch));

const stage6Prompt = [ctx.prompts.agent3_draft, 'Return JSON only.', 'Topic brief: ' + shortText(JSON.stringify(topicBrief), 1200), 'LinkedIn prep: ' + shortText(JSON.stringify(linkedinResearch), 2200), 'Reddit prep: ' + shortText(JSON.stringify(redditResearch), 2200), 'Evidence packets: ' + JSON.stringify(compactEvidence(evidencePackets, 3))].join('\n\n');
const stage6 = await callOllamaJson.call(this, 'You are a senior B2B social copywriter. Return valid JSON only.', stage6Prompt, { temperature: 0.25, num_predict: 140, num_ctx: 768, timeout: 180000, max_attempts: 3 });
let draftPackage = normalizeDraftPackage(stage6.parsed, topicBrief.topic);
validateDraftPackageStrict(draftPackage);
const linkedinDraft = draftPackage.drafts.find((d) => d.platform === 'linkedin') || draftPackage.drafts[0];
const redditDraft = draftPackage.drafts.find((d) => d.platform === 'reddit') || draftPackage.drafts[1] || draftPackage.drafts[0];
draftPackage.drafts = [linkedinDraft, redditDraft];
ctx.artifacts.draft_package = draftPackage;
addStage(6, 'build_draft_entwuerfe', 'ok', 'run/' + ctx.run_id + '/stage6/input', 'run/' + ctx.run_id + '/stage6/draft_package', 8.1, 'drafts=' + draftPackage.drafts.length);
await addStageSummary.call(this, 6, 'build_draft_entwuerfe', JSON.stringify(draftPackage));

const stage7Prompt = [ctx.prompts.agent4_ai_sounding_critic, 'Return JSON only.', 'Draft package: ' + JSON.stringify(compactDraftPackage(draftPackage))].join('\n\n');
const stage7 = await callOllamaJson.call(this, 'You improve text naturalness while preserving meaning. Return valid JSON only.', stage7Prompt, { temperature: 0.2, num_predict: 110, num_ctx: 768, timeout: 150000, max_attempts: 3 });
const critique7 = normalizeCritique(stage7.parsed, 'ai_kritik');
if (critique7.improved_draft?.drafts) draftPackage = normalizeDraftPackage(critique7.improved_draft, draftPackage.topic);
ctx.artifacts.critique_ai = critique7;
addStage(7, 'run_ai_kritik', 'ok', 'run/' + ctx.run_id + '/stage7/input', 'run/' + ctx.run_id + '/stage7/critique', critique7.score, 'issues=' + critique7.issues.length, critique7.issues.length);
await addStageSummary.call(this, 7, 'run_ai_kritik', JSON.stringify(critique7));

const stage8Prompt = [ctx.prompts.agent6_strategy_critic, 'Return JSON only.', 'Draft package: ' + JSON.stringify(compactDraftPackage(draftPackage)), 'Topic brief: ' + shortText(JSON.stringify(topicBrief), 1200)].join('\n\n');
const stage8 = await callOllamaJson.call(this, 'You review strategy quality and improve weak assumptions. Return valid JSON only.', stage8Prompt, { temperature: 0.2, num_predict: 110, num_ctx: 768, timeout: 150000, max_attempts: 3 });
const critique8 = normalizeCritique(stage8.parsed, 'strategie_kritik_1');
if (critique8.improved_draft?.drafts) draftPackage = normalizeDraftPackage(critique8.improved_draft, draftPackage.topic);
ctx.artifacts.critique_strategy_1 = critique8;
addStage(8, 'run_strategie_kritik_1', 'ok', 'run/' + ctx.run_id + '/stage8/input', 'run/' + ctx.run_id + '/stage8/critique', critique8.score, 'issues=' + critique8.issues.length, critique8.issues.length);
await addStageSummary.call(this, 8, 'run_strategie_kritik_1', JSON.stringify(critique8));

const stage9Prompt = [ctx.prompts.agent7_strategy_critic, 'Return JSON only.', 'Draft package: ' + JSON.stringify(compactDraftPackage(draftPackage)), 'Topic brief: ' + shortText(JSON.stringify(topicBrief), 1200)].join('\n\n');
const stage9 = await callOllamaJson.call(this, 'You run the strict final quality review. Return valid JSON only.', stage9Prompt, { temperature: 0.2, num_predict: 110, num_ctx: 768, timeout: 150000, max_attempts: 3 });
const critique9 = normalizeCritique(stage9.parsed, 'strategie_kritik_2');
if (critique9.improved_draft?.drafts) draftPackage = normalizeDraftPackage(critique9.improved_draft, draftPackage.topic);
ctx.artifacts.critique_strategy_2 = critique9;
ctx.artifacts.final_draft_package = draftPackage;
addStage(9, 'run_strategie_kritik_2', 'ok', 'run/' + ctx.run_id + '/stage9/input', 'run/' + ctx.run_id + '/stage9/critique', critique9.score, 'issues=' + critique9.issues.length, critique9.issues.length);
await addStageSummary.call(this, 9, 'run_strategie_kritik_2', JSON.stringify(critique9));

const topic = String(draftPackage.topic || topicBrief.topic || 'Workflow Thema');
const slug = sanitizeSlug(topic);
const date = nowIso().slice(0, 10);
const linkedinFinalDraft = draftPackage.drafts.find((d) => d.platform === 'linkedin') || draftPackage.drafts[0];
const redditFinalDraft = draftPackage.drafts.find((d) => d.platform === 'reddit') || draftPackage.drafts[1] || draftPackage.drafts[0];
const evidenceRefs = evidencePackets.map((p) => String(p.url || '').trim()).filter(Boolean).slice(0, 8);

const linkedinResearchPath = ctx.workflow_results_dir + '/' + ctx.run_id + ' - linkedin-ausarbeitung.md';
const redditResearchPath = ctx.workflow_results_dir + '/' + ctx.run_id + ' - reddit-ausarbeitung.md';
const linkedinDraftPath = ctx.workflow_drafts_dir + '/LinkedIn/' + date + ' - linkedin - ' + slug + '.md';
const redditDraftPath = ctx.workflow_drafts_dir + '/Reddit/' + date + ' - reddit - ' + slug + '.md';

const linkedinResearchMarkdown = ['# LinkedIn Ausarbeitung', '', '- run_id: ' + ctx.run_id, '- topic: ' + topic, '- platform: linkedin', '- model_used: ' + ctx.model_used, '', '## Kernproblem', String(linkedinResearch.core_problem || ''), '', '## Insight Angles', ensureArray(linkedinResearch.insight_angles).map((v) => '- ' + String(v)).join('\n') || '- n/a', '', '## Proof Points', ensureArray(linkedinResearch.proof_points).map((v) => '- ' + String(v)).join('\n') || '- n/a', '', '## Hook Optionen', ensureArray(linkedinResearch.hook_options).map((v) => '- ' + String(v)).join('\n') || '- n/a', '', '## CTA Optionen', ensureArray(linkedinResearch.cta_options).map((v) => '- ' + String(v)).join('\n') || '- n/a'].join('\n');
const redditResearchMarkdown = ['# Reddit Ausarbeitung', '', '- run_id: ' + ctx.run_id, '- topic: ' + topic, '- platform: reddit', '- model_used: ' + ctx.model_used, '', '## Kernproblem', String(redditResearch.core_problem || ''), '', '## Praktische Takeaways', ensureArray(redditResearch.practical_takeaways).map((v) => '- ' + String(v)).join('\n') || '- n/a', '', '## Proof Points', ensureArray(redditResearch.proof_points).map((v) => '- ' + String(v)).join('\n') || '- n/a', '', '## Titel Optionen', ensureArray(redditResearch.title_options).map((v) => '- ' + String(v)).join('\n') || '- n/a', '', '## Discussion Prompts', ensureArray(redditResearch.discussion_prompts).map((v) => '- ' + String(v)).join('\n') || '- n/a'].join('\n');

const linkedinDraftMarkdown = ['---', 'Datum: ' + date, 'run_id: ' + ctx.run_id, 'Plattform: LinkedIn', 'Zielgruppe: B2B Marketing und Data Teams', 'Beitragstyp: Textbeitrag', 'Thema: "' + yamlEscape(topic) + '"', 'Hook: "' + yamlEscape(linkedinFinalDraft.title || '') + '"', 'Status: draft', 'model_used: ' + ctx.model_used, 'quality_score: ' + clamp(critique9.score, 0, 10, 6), 'evidence_refs:', evidenceRefs.map((url) => '  - ' + url).join('\n') || '  - n/a', '---', '', '# ' + String(linkedinFinalDraft.title || topic), '', '## Beitrag', String(linkedinFinalDraft.body || ''), '', '## CTA', String(linkedinFinalDraft.cta || ''), '', '## Hashtags', ensureArray(linkedinFinalDraft.hashtags).join(' ')].join('\n');
const redditDraftMarkdown = ['---', 'Datum: ' + date, 'run_id: ' + ctx.run_id, 'Plattform: Reddit', 'Zielgruppe: Tech und Builder Community', 'Beitragstyp: Diskussionsthread', 'Thema: "' + yamlEscape(topic) + '"', 'Hook: "' + yamlEscape(redditFinalDraft.title || '') + '"', 'Status: draft', 'model_used: ' + ctx.model_used, 'quality_score: ' + clamp(critique9.score, 0, 10, 6), 'evidence_refs:', evidenceRefs.map((url) => '  - ' + url).join('\n') || '  - n/a', '---', '', '# ' + String(redditFinalDraft.title || topic), '', '## Beitrag', String(redditFinalDraft.body || ''), '', '## CTA', String(redditFinalDraft.cta || ''), '', '## Hashtags', ensureArray(redditFinalDraft.hashtags).join(' ')].join('\n');

const minQualityScore = Number.isFinite(Number($env.WF90_MIN_QUALITY_SCORE)) ? Number($env.WF90_MIN_QUALITY_SCORE) : 6.5;
const minEvidenceRefs = Number.isFinite(Number($env.WF90_MIN_EVIDENCE_REFS)) ? Number($env.WF90_MIN_EVIDENCE_REFS) : 3;
const minDraftBodyLen = Number.isFinite(Number($env.WF90_MIN_DRAFT_BODY_LEN)) ? Number($env.WF90_MIN_DRAFT_BODY_LEN) : 180;
const qualityFailures = [];
if (Number(critique9.score || 0) < minQualityScore) qualityFailures.push('quality_score<' + minQualityScore);
if (evidenceRefs.length < minEvidenceRefs) qualityFailures.push('evidence_refs<' + minEvidenceRefs);
if (String(linkedinFinalDraft.body || '').trim().length < minDraftBodyLen) qualityFailures.push('linkedin_body_too_short');
if (String(redditFinalDraft.body || '').trim().length < minDraftBodyLen) qualityFailures.push('reddit_body_too_short');
if (qualityFailures.length) throw new Error('Quality gate failed: ' + qualityFailures.join(', '));

ctx.topic = topic;
ctx.completed_at = nowIso();
ctx.status = 'pipeline_ok';
ctx.output_paths = {
  linkedin_research: linkedinResearchPath,
  reddit_research: redditResearchPath,
  linkedin_draft: linkedinDraftPath,
  reddit_draft: redditDraftPath,
  workflow_log: ctx.workflow_logs_dir + '/' + ctx.run_id + '.md',
};
ctx.generated = {
  linkedin_research_markdown: linkedinResearchMarkdown,
  reddit_research_markdown: redditResearchMarkdown,
  linkedin_draft_markdown: linkedinDraftMarkdown,
  reddit_draft_markdown: redditDraftMarkdown,
};

return [{ json: ctx }];
